"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[2842],{2786(t,e,i){i.r(e),i.d(e,{comp:()=>a,data:()=>d});var n=i(641);const r={},a=(0,i(6262).A)(r,[["render",function(t,e){return(0,n.uX)(),(0,n.CE)("div",null,[...e[0]||(e[0]=[(0,n.Fv)('<h1 id="email-notifications" tabindex="-1"><a class="header-anchor" href="#email-notifications"><span>Email Notifications</span></a></h1><p>21 transactional emails ship with the plugin. All editable from <strong>WooCommerce → Settings → Emails</strong>.</p><h2 id="all-21-emails" tabindex="-1"><a class="header-anchor" href="#all-21-emails"><span>All 21 emails</span></a></h2><table><thead><tr><th>Email</th><th>Trigger</th><th>Recipients</th></tr></thead><tbody><tr><td><strong>Bid placed</strong></td><td>Bidder successfully places a bid</td><td>Bidder, admin, seller</td></tr><tr><td><strong>Outbid</strong></td><td>Another bid beats the user&#39;s</td><td>Previous high bidder</td></tr><tr><td><strong>Auction starting</strong></td><td>A scheduled auction goes live</td><td>Watchers + registered bidders</td></tr><tr><td><strong>Auction started</strong></td><td>(optional admin announcement)</td><td>All registered users</td></tr><tr><td><strong>Auction ending soon</strong></td><td>A configurable interval before close</td><td>Active bidders + watchers</td></tr><tr><td><strong>Auction won</strong></td><td>User wins</td><td>Winner</td></tr><tr><td><strong>Auction lost</strong></td><td>User bid but didn&#39;t win</td><td>Non-winning bidders</td></tr><tr><td><strong>Payment reminder</strong></td><td>A configurable interval after win, unpaid</td><td>Winner</td></tr><tr><td><strong>Payment confirmation</strong></td><td>Payment completed</td><td>Winner, seller, admin</td></tr><tr><td><strong>Payment overdue</strong></td><td>Past the payment deadline</td><td>Winner, admin</td></tr><tr><td><strong>Auction failed</strong></td><td>Reserve not met</td><td>Seller, bidders</td></tr><tr><td><strong>Auction relisted</strong></td><td><a href="/auto-relist.html" target="_blank" rel="noopener noreferrer">Auto-relist</a> triggers</td><td>Previous bidders + watchers</td></tr><tr><td><strong>Watchlist activity</strong></td><td>Configured trigger on a watched lot</td><td>Watcher</td></tr><tr><td><strong>Registration</strong></td><td>New user signup</td><td>New user</td></tr><tr><td><strong>New auction from seller</strong></td><td>Vendor publishes a lot</td><td>Seller-followers</td></tr><tr><td><strong>Lot approved</strong></td><td>Admin approves vendor lot</td><td>Vendor</td></tr><tr><td><strong>Lot rejected</strong></td><td>Admin rejects vendor lot</td><td>Vendor</td></tr><tr><td><strong>Seller application received</strong></td><td>(legacy — vendor onboarding moved to multi-vendor plugin)</td><td>Applicant</td></tr><tr><td><strong>Seller approved</strong></td><td>(legacy)</td><td>Applicant</td></tr><tr><td><strong>Seller rejected</strong></td><td>(legacy)</td><td>Applicant</td></tr></tbody></table><h2 id="where-to-edit-them" tabindex="-1"><a class="header-anchor" href="#where-to-edit-them"><span>Where to edit them</span></a></h2><p><strong>WooCommerce → Settings → Emails</strong> lists every email. Click one to:</p><ul><li>Enable / disable</li><li>Override the recipient (admin emails)</li><li>Override the subject line</li><li>Override the heading</li><li>Override the email body (HTML / plain text)</li><li>Tweak the template via WooCommerce&#39;s standard email customiser</li></ul><h2 id="localisation" tabindex="-1"><a class="header-anchor" href="#localisation"><span>Localisation</span></a></h2><p>Email text is fully translatable. Use:</p><ul><li>WordPress&#39;s built-in translation tooling</li><li>Loco Translate plugin</li><li>WPML / Polylang for multi-language sites</li></ul><p>Emails respect the recipient&#39;s user locale.</p><h2 id="email-digest" tabindex="-1"><a class="header-anchor" href="#email-digest"><span>Email digest</span></a></h2><p>For low-priority notifications, customers can opt into a <strong>daily digest</strong>:</p><table><thead><tr><th>Setting</th><th>Effect</th></tr></thead><tbody><tr><td>Digest enabled (per user)</td><td>Bundles non-urgent notifications</td></tr><tr><td>Digest send time</td><td>User&#39;s preferred hour</td></tr><tr><td>Digest frequency</td><td>Daily / Weekly</td></tr></tbody></table><p>Time-sensitive notifications (outbid, won, ending soon) always fire individually regardless of the digest setting.</p><h2 id="plain-text-versions" tabindex="-1"><a class="header-anchor" href="#plain-text-versions"><span>Plain-text versions</span></a></h2><p>Each HTML template ships with a plain-text counterpart. WooCommerce automatically attaches the plain-text version as a fallback for email clients that prefer it.</p><h2 id="sending-mechanics" tabindex="-1"><a class="header-anchor" href="#sending-mechanics"><span>Sending mechanics</span></a></h2><p>The plugin uses WooCommerce&#39;s email engine — same as standard WC emails. This means it respects WC&#39;s &quot;from&quot; address and name, works with any standard SMTP plugin, and shows up in any SMTP plugin&#39;s send log.</p><p>For high-volume sites, queued sends (digests, bulk &quot;ending soon&quot; blasts) go through Action Scheduler so they never block a bid request.</p><h2 id="specific-email-reference" tabindex="-1"><a class="header-anchor" href="#specific-email-reference"><span>Specific email reference</span></a></h2><h3 id="bid-placed" tabindex="-1"><a class="header-anchor" href="#bid-placed"><span>Bid placed</span></a></h3><p>Sent immediately after a bid is accepted:</p><table><thead><tr><th>Recipient</th><th>Subject</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Bidder</strong></td><td>&quot;Bid placed — {title}&quot;</td><td>Confirms the bid, shows amount</td></tr><tr><td><strong>Admin</strong></td><td>&quot;New bid: {title}&quot;</td><td>Admin awareness, especially on high-value lots</td></tr><tr><td><strong>Seller</strong></td><td>&quot;New bid on your auction&quot;</td><td>Vendor awareness</td></tr></tbody></table><p>Configurable per-recipient.</p><h3 id="outbid" tabindex="-1"><a class="header-anchor" href="#outbid"><span>Outbid</span></a></h3><p>Sent when another bid beats the user&#39;s current high.</p><blockquote><p>Subject: &quot;You&#39;ve been outbid on {title}&quot;</p></blockquote><p>The body includes the new high amount, a one-click rebid button (jumps to the auction with the minimum increment pre-filled) and the time remaining.</p><h3 id="auction-won" tabindex="-1"><a class="header-anchor" href="#auction-won"><span>Auction won</span></a></h3><blockquote><p>Subject: &quot;🎉 You won {title}!&quot;</p></blockquote><p>The body includes the winning amount, a Pay Now button (or &quot;paid via wallet&quot; confirmation if <a href="/wallet-auto-charge.html" target="_blank" rel="noopener noreferrer">auto-charged</a>), the payment deadline and seller contact info.</p><h3 id="watchlist-activity" tabindex="-1"><a class="header-anchor" href="#watchlist-activity"><span>Watchlist activity</span></a></h3><p>A watcher can opt in or out of each of these sub-triggers:</p><table><thead><tr><th>Sub-trigger</th><th>Default</th></tr></thead><tbody><tr><td>Auction starting (24 hr)</td><td>yes</td></tr><tr><td>Auction starting (1 hr)</td><td>yes</td></tr><tr><td>Reserve met for the first time</td><td>yes</td></tr><tr><td>Auction ending soon (1 hr)</td><td>yes</td></tr><tr><td>Auction ending soon (5 min)</td><td>optional</td></tr><tr><td>First bid placed</td><td>optional</td></tr><tr><td>Auction ended (won by another)</td><td>optional</td></tr></tbody></table><p><a href="/watchlist.html" target="_blank" rel="noopener noreferrer">Watchlist →</a></p><h2 id="performance" tabindex="-1"><a class="header-anchor" href="#performance"><span>Performance</span></a></h2><p>Email sending is queued in the background — never blocks a bid request. Even on a slow SMTP server, bid placement remains fast.</p><p>For very high bid volume, consider a dedicated email service (Postmark, SendGrid, Amazon SES), enabling digest mode for non-critical events, or batching the &quot;auction ending soon&quot; blast as one mass send instead of per-user.</p><h2 id="common-questions" tabindex="-1"><a class="header-anchor" href="#common-questions"><span>Common questions</span></a></h2><p><strong>&quot;Email isn&#39;t arriving?&quot;</strong></p><p>Standard WordPress email troubleshooting:</p><ol><li>Check <strong>WP → Tools → Site Health</strong> for &quot;PHP mail&quot; issues.</li><li>Use an SMTP plugin (WP Mail SMTP, FluentSMTP).</li><li>Check the spam folder.</li><li>Verify the recipient&#39;s email is verified.</li><li>Check your domain&#39;s SPF / DKIM / DMARC records.</li></ol><p><strong>&quot;Why is my email going to spam?&quot;</strong></p><p>The most common cause is missing DKIM / SPF records. Configure your domain DNS per your SMTP provider&#39;s instructions.</p>',45)])])}]]),d=JSON.parse('{"path":"/notifications.html","title":"Email Notifications","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"All 21 emails","slug":"all-21-emails","link":"#all-21-emails","children":[]},{"level":2,"title":"Where to edit them","slug":"where-to-edit-them","link":"#where-to-edit-them","children":[]},{"level":2,"title":"Localisation","slug":"localisation","link":"#localisation","children":[]},{"level":2,"title":"Email digest","slug":"email-digest","link":"#email-digest","children":[]},{"level":2,"title":"Plain-text versions","slug":"plain-text-versions","link":"#plain-text-versions","children":[]},{"level":2,"title":"Sending mechanics","slug":"sending-mechanics","link":"#sending-mechanics","children":[]},{"level":2,"title":"Specific email reference","slug":"specific-email-reference","link":"#specific-email-reference","children":[{"level":3,"title":"Bid placed","slug":"bid-placed","link":"#bid-placed","children":[]},{"level":3,"title":"Outbid","slug":"outbid","link":"#outbid","children":[]},{"level":3,"title":"Auction won","slug":"auction-won","link":"#auction-won","children":[]},{"level":3,"title":"Watchlist activity","slug":"watchlist-activity","link":"#watchlist-activity","children":[]}]},{"level":2,"title":"Performance","slug":"performance","link":"#performance","children":[]},{"level":2,"title":"Common questions","slug":"common-questions","link":"#common-questions","children":[]}],"git":{},"filePathRelative":"notifications.md"}')}}]);